//! Routes module
//!
//! This file is generated by runts during the build process.

use axum::{Router, response::IntoResponse};
use serde::{Serialize, Deserialize};

/// Route table
pub fn routes() -> Vec<Route> {
    vec![
        Route {
            pattern: "/",
            methods: vec![Method::GET],
            params: vec![],
        },
        Route {
            pattern: "/blog",
            methods: vec![Method::GET],
            params: vec![],
        },
        Route {
            pattern: "/blog/:slug",
            methods: vec![Method::GET],
            params: vec!["slug"],
        },
    ]
}

/// HTTP method
#[derive(Debug, Clone)]
pub enum Method {
    GET,
    POST,
    PUT,
    DELETE,
}

/// Route entry
#[derive(Debug, Clone)]
pub struct Route {
    pub pattern: &'static str,
    pub methods: Vec<Method>,
    pub params: Vec<&'static str>,
}

/// Build the application router
pub fn build_router() -> Router {
    use axum::routing::get;
    
    let app = Router::new()
        .route("/", get(index_handler))
        .route("/blog", get(blog_index_handler))
        .route("/blog/:slug", get(blog_post_handler));
    
    app
}

// Route handlers

async fn index_handler() -> impl IntoResponse {
    let html = r#"
        <!DOCTYPE html>
        <html>
        <head><title>Welcome</title></head>
        <body>
            <h1>Welcome to runts!</h1>
            <p>This is a server-rendered page.</p>
            <div data-island="Counter" data-hydration="lazy">
                <p>Count: 0</p>
            </div>
        </body>
        </html>
    "#;
    
    axum::response::Html(html)
}

async fn blog_index_handler() -> impl IntoResponse {
    let posts = serde_json::json!([
        { "slug": "hello-world", "title": "Hello, World!", "date": "2024-01-15" },
        { "slug": "rust-and-fresh", "title": "Rust and Fresh", "date": "2024-01-20" }
    ]);
    
    let html = format!(
        r#"
        <!DOCTYPE html>
        <html>
        <head><title>Blog</title></head>
        <body>
            <h1>Blog</h1>
            <ul>
                {}
            </ul>
        </body>
        </html>
        "#,
        posts.as_array().unwrap()
            .iter()
            .map(|p| format!(
                r#"<li><a href="/blog/{}">{}</a></li>"#,
                p["slug"], p["title"]
            ))
            .collect::<Vec<_>>()
            .join("\n")
    );
    
    axum::response::Html(html)
}

async fn blog_post_handler(axum::extract::Path(slug): axum::extract::Path<String>) -> impl IntoResponse {
    let posts: std::collections::HashMap<&str, (&str, &str)> = std::collections::HashMap::from([
        ("hello-world", ("Hello, World!", "This is my first blog post.")),
        ("rust-and-fresh", ("Rust and Fresh", "Building with Rust is amazing.")),
    ]);
    
    match posts.get(slug.as_str()) {
        Some((title, content)) => {
            let html = format!(
                r#"
                <!DOCTYPE html>
                <html>
                <head><title>{}</title></head>
                <body>
                    <h1>{}</h1>
                    <p>{}</p>
                    <a href="/blog">Back to blog</a>
                </body>
                </html>
                "#,
                title, title, content
            );
            axum::response::Html(html)
        }
        None => {
            (axum::http::StatusCode::NOT_FOUND, "Post not found")
        }
    }
}
